+/**
+ * Preferences service — manages user notification preferences.
+ *
+ * Provides CRUD operations for user preferences and exposes a
+ * query method for the NotificationService to check whether a
+ * notification should be delivered.
+ *
+ * Depends on:
+ * - PreferencesRepository for persistence
+ */
+
+import type { PreferencesRepository } from '../repositories/preferences.repository.js';
+import type {
+  UserPreferences,
+  UpdateEmailPreferencesInput,
+} from '../models/user-preferences.js';
+import type { NotificationType } from '../models/notification.js';
+import { getDefaultEmailPreferences } from '../models/user-preferences.js';
+import { Logger } from '../utils/logger.js';
+
+let nextId = 1;
+
+function generatePreferencesId(): string {
+  return `pref-${String(nextId++).padStart(4, '0')}`;
+}
+
+/** Reset the ID counter (for testing). */
+export function resetPreferencesIdCounter(): void {
+  nextId = 1;
+}
+
+export class PreferencesService {
+  private logger = new Logger('PreferencesService');
+
+  constructor(private repository: PreferencesRepository) {}
+
+  /**
+   * Get preferences for a user. Returns undefined if none exist.
+   */
+  getPreferences(userId: string): UserPreferences | undefined {
+    return this.repository.findByUserId(userId);
+  }
+
+  /**
+   * Get preferences for a user, creating defaults if none exist.
+   */
+  getOrCreatePreferences(userId: string): UserPreferences {
+    const existing = this.repository.findByUserId(userId);
+    if (existing) {
+      return existing;
+    }
+
+    const now = new Date();
+    const prefs: UserPreferences = {
+      id: generatePreferencesId(),
+      userId,
+      email: getDefaultEmailPreferences(),
+      createdAt: now,
+      updatedAt: now,
+    };
+
+    this.repository.save(prefs);
+    this.logger.info(`Created default preferences for user: ${userId}`);
+    return prefs;
+  }
+
+  /**
+   * Update email preferences for a user. Creates defaults first if none exist.
+   * Only provided fields in the input are changed.
+   */
+  updateEmailPreferences(userId: string, input: UpdateEmailPreferencesInput): UserPreferences {
+    const current = this.getOrCreatePreferences(userId);
+
+    const updatedEmail = { ...current.email };
+
+    if (input.enabled !== undefined) {
+      updatedEmail.enabled = input.enabled;
+    }
+    if (input.frequency !== undefined) {
+      updatedEmail.frequency = input.frequency;
+    }
+    if (input.categories !== undefined) {
+      updatedEmail.categories = { ...updatedEmail.categories, ...input.categories };
+    }
+
+    const updated = this.repository.update(current.id, {
+      email: updatedEmail,
+      updatedAt: new Date(),
+    });
+
+    this.logger.info(`Updated email preferences for user: ${userId}`);
+    return updated;
+  }
+
+  /**
+   * Check whether a notification of the given type should be sent to a user via email.
+   *
+   * Returns true if:
+   * - The user has no preferences (defaults allow all)
+   * - Email is enabled AND the specific category is subscribed
+   */
+  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
+    const prefs = this.repository.findByUserId(userId);
+
+    // No preferences stored — default is to send everything
+    if (!prefs) {
+      return true;
+    }
+
+    // Email globally disabled
+    if (!prefs.email.enabled) {
+      return false;
+    }
+
+    // Check category-level subscription
+    return prefs.email.categories[notificationType] !== false;
+  }
+
+  /**
+   * Delete preferences for a user (resets to defaults on next access).
+   */
+  deletePreferences(userId: string): boolean {
+    const prefs = this.repository.findByUserId(userId);
+    if (!prefs) {
+      return false;
+    }
+    this.repository.delete(prefs.id);
+    this.logger.info(`Deleted preferences for user: ${userId}`);
+    return true;
+  }
+}

