import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationService, resetNotificationIdCounter } from '../../src/services/notification.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import type { OrderCreatedEvent, UserUpdatedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let repository: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repository = new PreferencesRepository(db);
    service = new PreferencesService(repository);
    resetPreferencesIdCounter();
  });

  describe('getPreferences', () => {
    it('should return undefined when no preferences exist', () => {
      expect(service.getPreferences('user-1')).toBeUndefined();
    });

    it('should return preferences after they are created', () => {
      service.getOrCreatePreferences('user-1');
      const prefs = service.getPreferences('user-1');
      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-1');
    });
  });

  describe('getOrCreatePreferences', () => {
    it('should create default preferences for a new user', () => {
      const prefs = service.getOrCreatePreferences('user-1');

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.categories.order_confirmation).toBe(true);
      expect(prefs.email.categories.order_status_update).toBe(true);
      expect(prefs.email.categories.welcome).toBe(true);
      expect(prefs.email.categories.account_updated).toBe(true);
    });

    it('should return existing preferences without creating duplicates', () => {
      const first = service.getOrCreatePreferences('user-1');
      const second = service.getOrCreatePreferences('user-1');

      expect(first.id).toBe(second.id);
      expect(first.userId).toBe(second.userId);
    });

    it('should generate sequential IDs for different users', () => {
      const prefs1 = service.getOrCreatePreferences('user-1');
      const prefs2 = service.getOrCreatePreferences('user-2');

      expect(prefs1.id).toBe('pref-0001');
      expect(prefs2.id).toBe('pref-0002');
    });
  });

  describe('updateEmailPreferences', () => {
    it('should disable email notifications', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', { enabled: false });

      expect(updated.email.enabled).toBe(false);
      // Other fields should be unchanged
      expect(updated.email.frequency).toBe('immediate');
      expect(updated.email.categories.order_confirmation).toBe(true);
    });

    it('should update frequency', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', { frequency: 'daily_digest' });

      expect(updated.email.frequency).toBe('daily_digest');
      expect(updated.email.enabled).toBe(true);
    });

    it('should update individual category subscriptions', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', {
        categories: { account_updated: false },
      });

      expect(updated.email.categories.account_updated).toBe(false);
      // Other categories should remain subscribed
      expect(updated.email.categories.order_confirmation).toBe(true);
      expect(updated.email.categories.order_status_update).toBe(true);
      expect(updated.email.categories.welcome).toBe(true);
    });

    it('should update multiple fields at once', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', {
        frequency: 'weekly_digest',
        categories: { welcome: false, account_updated: false },
      });

      expect(updated.email.frequency).toBe('weekly_digest');
      expect(updated.email.categories.welcome).toBe(false);
      expect(updated.email.categories.account_updated).toBe(false);
      expect(updated.email.categories.order_confirmation).toBe(true);
    });

    it('should create defaults before updating if no preferences exist', () => {
      const updated = service.updateEmailPreferences('user-1', { enabled: false });

      expect(updated.userId).toBe('user-1');
      expect(updated.email.enabled).toBe(false);
      // Default categories should still be present
      expect(updated.email.categories.order_confirmation).toBe(true);
    });

    it('should persist changes across lookups', () => {
      service.updateEmailPreferences('user-1', {
        categories: { welcome: false },
      });

      const fetched = service.getPreferences('user-1');
      expect(fetched!.email.categories.welcome).toBe(false);
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true when no preferences exist (defaults allow all)', () => {
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(true);
    });

    it('should return true when email is enabled and category is subscribed', () => {
      service.getOrCreatePreferences('user-1');
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false when email is globally disabled', () => {
      service.updateEmailPreferences('user-1', { enabled: false });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'account_updated')).toBe(false);
    });

    it('should return false when category is unsubscribed', () => {
      service.updateEmailPreferences('user-1', {
        categories: { account_updated: false },
      });

      expect(service.shouldSendEmail('user-1', 'account_updated')).toBe(false);
      // Other categories should still be allowed
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });

    it('should respect re-enabling a category', () => {
      service.updateEmailPreferences('user-1', {
        categories: { welcome: false },
      });
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(false);

      service.updateEmailPreferences('user-1', {
        categories: { welcome: true },
      });
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(true);
    });
  });

  describe('deletePreferences', () => {
    it('should return false when no preferences exist', () => {
      expect(service.deletePreferences('user-1')).toBe(false);
    });

    it('should delete existing preferences', () => {
      service.getOrCreatePreferences('user-1');
      expect(service.deletePreferences('user-1')).toBe(true);
      expect(service.getPreferences('user-1')).toBeUndefined();
    });

    it('should reset to defaults on next access after deletion', () => {
      service.updateEmailPreferences('user-1', { enabled: false });
      service.deletePreferences('user-1');

      // After deletion, shouldSendEmail falls back to default (true)
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });
  });
});

describe('NotificationService with preferences', () => {
  let db: Database;
  let preferencesRepository: PreferencesRepository;
  let preferencesService: PreferencesService;
  let eventBus: EventBus;
  let notificationService: NotificationService;

  beforeEach(() => {
    db = new Database();
    preferencesRepository = new PreferencesRepository(db);
    preferencesService = new PreferencesService(preferencesRepository);
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    resetNotificationIdCounter();
    resetPreferencesIdCounter();
    notificationService = new NotificationService(eventBus, [], preferencesService);
  });

  it('should send notifications when user has no preferences', async () => {
    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(notificationService.getNotificationCount()).toBe(1);
  });

  it('should suppress notifications when user has email disabled', async () => {
    preferencesService.updateEmailPreferences('user-1', { enabled: false });

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should suppress notifications for unsubscribed categories', async () => {
    preferencesService.updateEmailPreferences('user-1', {
      categories: { account_updated: false },
    });

    const event: UserUpdatedEvent = {
      type: 'user:updated',
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      changes: ['name'],
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should still send subscribed categories while others are unsubscribed', async () => {
    preferencesService.updateEmailPreferences('user-1', {
      categories: { account_updated: false },
    });

    // This should be sent (order_confirmation is still subscribed)
    const orderEvent: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    // This should be suppressed (account_updated is unsubscribed)
    const updateEvent: UserUpdatedEvent = {
      type: 'user:updated',
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      changes: ['email'],
      timestamp: new Date(),
    };

    await eventBus.emit(orderEvent);
    await eventBus.emit(updateEvent);

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(1);
    expect(notifications[0]?.subject).toContain('Order Confirmation');
  });

  it('should work without preferences service (backward compatible)', async () => {
    const serviceWithoutPrefs = new NotificationService(eventBus);

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    // Two notifications: one from notificationService (with prefs), one from serviceWithoutPrefs
    // But we're checking serviceWithoutPrefs specifically
    expect(serviceWithoutPrefs.getNotificationCount()).toBe(1);
  });
});
